import{c as t,Q as a,j as i,m as n}from"./chunks/framework.DpF7k2f3.js";const d=JSON.parse('{"title":"Chapter 1: The Truth About AI Application Development","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en/part1-cognition/chapter1.md","filePath":"en/part1-cognition/chapter1.md","lastUpdated":1779671667000}'),o={name:"en/part1-cognition/chapter1.md"};function r(s,e,l,p,h,c){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="chapter-1-the-truth-about-ai-application-development" tabindex="-1">Chapter 1: The Truth About AI Application Development <a class="header-anchor" href="#chapter-1-the-truth-about-ai-application-development" aria-label="Permalink to &quot;Chapter 1: The Truth About AI Application Development&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>Before reading this chapter, you might think AI application development is an inaccessible field—requiring a PhD, understanding of Transformer architecture, and strong mathematical foundations.</p><p>After reading this chapter, you will know:</p><ul><li>AI application development and AI research are two different things, with completely different entry barriers</li><li>What happened in the industry from 2024-2026 and why now is the best time to enter</li><li>Which requirements in job postings are real and which are inflated</li><li>8 real career transition stories showing how people from different backgrounds got in</li></ul><hr><h2 id="_1-1-what-is-ai-application-development-vs-ai-research-infrastructure" tabindex="-1">1.1 What is AI Application Development (vs AI Research/Infrastructure) <a class="header-anchor" href="#_1-1-what-is-ai-application-development-vs-ai-research-infrastructure" aria-label="Permalink to &quot;1.1 What is AI Application Development (vs AI Research/Infrastructure)&quot;">​</a></h2><p>Let me tell you a harsh truth first: most people want to enter &quot;AI positions,&quot; but these aren&#39;t actually the &quot;AI positions&quot; they think they are.</p><h3 id="three-job-types-one-letter-difference-worlds-apart" tabindex="-1">Three Job Types, One Letter Difference, Worlds Apart <a class="header-anchor" href="#three-job-types-one-letter-difference-worlds-apart" aria-label="Permalink to &quot;Three Job Types, One Letter Difference, Worlds Apart&quot;">​</a></h3><p>I divide AI industry technical positions into three layers. Once you understand which layer you&#39;re aiming for, you won&#39;t take the wrong path:</p><p><strong>Layer 1: AI Research</strong></p><p>This is about making fundamental innovations. What do they do? Training new models, improving Transformer architecture, optimizing Attention mechanisms. This is what scientists at OpenAI, Google DeepMind, and Anthropic do.</p><p>How high is the barrier? Let&#39;s put it this way: globally, there are only tens of thousands of top talents who can truly excel at this level. You need: top conference papers, PhD degree (or equivalent research ability), solid math skills, and comprehensive knowledge of the latest papers.</p><p>Salary? Astronomical. But it has nothing to do with us.</p><p><strong>Layer 2: AI Infrastructure</strong></p><p>This layer builds tools for &quot;the layer above.&quot; What do they do? Training framework development (PyTorch/TensorFlow maintenance), inference engine optimization (vLLM/TensorRT), distributed training systems, GPU cluster management.</p><p>The barrier is also high. You need to understand system internals, C++ skills, and deep learning framework principles. Salaries are slightly lower than research positions, but still absolutely high-paying.</p><p><strong>Layer 3: AI Application Development</strong></p><p>This is what this book is about. And this is the layer you can most likely enter.</p><p>What do they do? Simply put, it&#39;s &quot;using AI capabilities to solve business problems.&quot; More specifically:</p><ul><li>Building RAG systems so LLMs can answer questions about private knowledge bases</li><li>Writing Prompts so AI outputs in the format you want</li><li>Building Agents so AI can automatically execute multi-step tasks</li><li>Integrating AI capabilities into products via API</li></ul><p>You don&#39;t need to train models, don&#39;t need to understand gradient backpropagation, don&#39;t need to derive Attention formulas by hand. What you need is: <strong>using existing AI capabilities well, applying them to business scenarios, and generating commercial value.</strong></p><hr><blockquote><p><strong>Full translation coming soon. You can read the Chinese version in the meantime.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part1-cognition/chapter1.html">阅读中文版</a></p></blockquote>',24)])])}const m=t(o,[["render",r]]);export{d as __pageData,m as default};
